import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Налаштування середовища розробки","description":"Покрокова інструкція щодо налаштування середовища розробки для створення модів за допомогою Fabric.","frontmatter":{"title":"Налаштування середовища розробки","description":"Покрокова інструкція щодо налаштування середовища розробки для створення модів за допомогою Fabric.","authors":["2xsaiko","Andrew6rant","asiekierka","Daomephsta","falseresync","IMB11","liach","mkpoli","modmuss50","natanfudge","SolidBlock-cn","TelepathicGrunt"],"authors-nogithub":["siglong"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.10/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.10/translated/uk_ua/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1766682904000}`);var o={name:`uk_ua/1.21.10/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Налаштування середовища розробки <a class="header-anchor" href="#h1" aria-label="Permalink to “Налаштування середовища розробки”">​</a></h1><p>Щоб розпочати розробку модів за допомогою Fabric, вам потрібно буде налаштувати середовище розробки за допомогою IntelliJ IDEA.</p><h2 id="installing-jdk-21" tabindex="-1">Установлення JDK 21 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “Установлення JDK 21”">​</a></h2><p>Для розробки модів для Minecraft 1.21.4 вам знадобиться JDK 21.</p><p>Якщо вам потрібна допомога щодо встановлення Java, ви можете звернутися до різних посібників із встановлення Java у <a href="./../../players/index">розділі посібників для гравців</a>.</p><h2 id="installing-intellij-idea" tabindex="-1">Установлення IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Установлення IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Очевидно, ви можете використовувати інші IDE, такі як Eclipse або Visual Studio Code, але на більшості сторінок цього сайту документації буде припущено, що ви використовуєте IntelliJ IDEA. Вам слід звернутися до документації для вашої IDE, якщо ви використовуєте іншу.</p></div><p>Якщо у вас не встановлено IntelliJ IDEA, ви можете завантажити його з <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">офіційного сайту</a> – дотримуйтеся вказівок із встановлення для вашої операційної системи.</p><p>Версія спільноти IntelliJ IDEA є безплатний та має відкритий вихідний код, і це рекомендована версія для модифікації за допомогою Fabric.</p><p>Можливо, вам доведеться прокрутити вниз, щоб знайти посилання для завантаження видання Community – воно виглядає так:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="Запит про завантаження версії IDEA Community Edition" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Встановлення плаґінів IDEA <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Встановлення плаґінів IDEA”">​</a></h2><p>Хоча ці плаґіни не є абсолютно необхідними, вони можуть значно полегшити модифікацію за допомогою Fabric – вам слід розглянути можливість їх встановлення.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>Плаґін Minecraft Development підтримує модифікацію за допомогою Fabric, і це найважливіший плаґін для встановлення.</p><p>Ви можете встановити його, відкривши IntelliJ IDEA, а потім перейшовши до <code>File &gt; Settings &gt; Plugins &gt; Marketplace</code> - знайдіть <code>Minecraft Development</code> у рядку пошуку, а потім натисніть кнопку <code>Install</code>.</p><p>Крім того, ви можете завантажити його зі <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">сторінки плаґінів</a>, а потім установити, перейшовши до <code>File &gt; Settings &gt; Plugins &gt; Install Plugin From Disk</code>.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};